#include <bits/stdc++.h>
using namespace std;

#define debug false

struct st {
    long long p, c;
} s[100005];
struct truck {
    long long a, b;
    long long c;
} t[100005];
int n, m, x;

bool cmp1(st a, st b) {
    return a.p < b.p;
}

bool cmp2(truck a, truck b) {
    return a.c > b.c;
}

int main() {
    cin >> n >> m >> x;
    for (int i = 0; i < n; i++) {
        cin >> s[i].p >> s[i].c;
    }
    for (int i = 0; i < m; i++) {
        cin >> t[i].a >> t[i].b;
        t[i].c = t[i].a - t[i].b;
    }
    sort(s, s + n, cmp1);
    sort(t, t + m, cmp2);
    long long ans = 0;
    int j = 0;
    for (int i = 0; i < m; i++) {
        if (debug) {
            printf(">>> t[i(%d)]:(a:%lld, b:%lld, c:%lld), s[j(%d)]:(c:%lld, p:%lld), ans: %lld  %s %s\n", 
                i, t[i].a, t[i].b, t[i].c, 
                j, s[j].c - 1, s[j].p,
                ans + 2 * (s[j].p * t[i].c + t[i].b * x),
                (t[i].c < 0 ? "break" : ""),
                (s[j].c == 1 ? "j++" : "")
            );
        }
        if (t[i].c < 0) break;
        ans += 2 * (s[j].p * t[i].c + t[i].b * x);
        if (--s[j].c == 0) {
            j++;
        }
    }
    j = n - 1;
    if (debug) printf(">>> \n");
    for (int i = m - 1; i >= 0; i--) {
        if (debug) {
            printf(">>> t[i(%d)]:(a:%lld, b:%lld, c:%lld), s[j(%d)]:(c:%lld, p:%lld), ans: %lld  %s %s\n", 
                i, t[i].a, t[i].b, t[i].c, 
                j, s[j].c - 1, s[j].p, 
                ans + 2 * (s[j].p * t[i].c + t[i].b * x),
                (t[i].c >= 0 ? "break" : ""),
                (s[j].c == 1 ? "j--" : "")
            );
        }
        if (t[i].c >= 0) break;
        ans += 2 * (s[j].p * t[i].c + t[i].b * x);
        if (--s[j].c == 0) {
            j--;
        }
    }
    cout << ans;
    return 0;
}
